import React, { useState, useEffect } from 'react';
import { getSuggestions } from '../services/api';

function OptimizationTips() {
  const [suggestions, setSuggestions] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchSuggestions = async () => {
      try {
        const response = await getSuggestions();
        console.log('💡 Suggestions received:', response.data);

        // Handle different response formats
        const suggestionsData = Array.isArray(response.data)
          ? response.data
          : (response.data?.suggestions || []);

        setSuggestions(Array.isArray(suggestionsData) ? suggestionsData : []);
        setLoading(false);
      } catch (error) {
        console.error('❌ Error fetching suggestions:', error);
        // Fallback suggestions
        setSuggestions([
          { icon: '💡', tip: 'Optimize model architecture to reduce computational complexity' },
          { icon: '⚡', tip: 'Use mixed precision training to reduce energy consumption' },
          { icon: '🔄', tip: 'Implement batch processing for better resource utilization' },
          { icon: '🌱', tip: 'Schedule training during off-peak hours for greener energy' }
        ]);
        setLoading(false);
      }
    };

    fetchSuggestions();
  }, []);

  const TipCard = ({ icon, tip, index }) => (
    <div
      className="glass-card fade-in"
      style={{
        padding: 'var(--spacing-lg)',
        display: 'flex',
        alignItems: 'flex-start',
        gap: '16px',
        animationDelay: `${index * 100}ms`,
        transition: 'all 0.3s ease'
      }}
    >
      <div style={{
        fontSize: '2rem',
        minWidth: '48px',
        height: '48px',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        background: 'var(--bg-card)',
        borderRadius: 'var(--radius-md)',
        border: '1px solid rgba(255, 255, 255, 0.1)'
      }}>
        {icon}
      </div>
      <p style={{
        margin: 0,
        color: 'var(--text-secondary)',
        fontSize: '0.95rem',
        lineHeight: 1.6,
        flex: 1
      }}>
        {tip}
      </p>
    </div>
  );

  return (
    <div className="glass-card fade-in" style={{
      padding: 'var(--spacing-xl)',
      animationDelay: '300ms'
    }}>
      <div style={{
        display: 'flex',
        alignItems: 'center',
        marginBottom: 'var(--spacing-lg)'
      }}>
        <div style={{
          width: '4px',
          height: '28px',
          background: 'var(--warning-gradient)',
          borderRadius: '2px',
          marginRight: '16px'
        }}></div>
        <h2 style={{
          fontSize: '1.5rem',
          fontWeight: 700,
          margin: 0,
          color: 'var(--text-primary)'
        }}>
          💡 Optimization Tips
        </h2>
      </div>

      {loading ? (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
          {[1, 2, 3].map(i => (
            <div key={i} className="shimmer" style={{
              height: '80px',
              borderRadius: 'var(--radius-md)'
            }}></div>
          ))}
        </div>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
          {Array.isArray(suggestions) && suggestions.map((suggestion, index) => (
            <TipCard
              key={index}
              icon={suggestion.icon || '💡'}
              tip={suggestion.tip || suggestion.message || String(suggestion)}
              index={index}
            />
          ))}
        </div>
      )}
    </div>
  );
}

export default OptimizationTips;
